SELECT SUM(number_of_deaths) AS total_deaths
FROM country_disease_data
WHERE country_id = 0 AND year = 2008;

SELECT number_of_deaths
FROM country_injury_data
WHERE country_id = 1 AND injury_id = 1 AND year = 2007;

SELECT number_of_deaths, incidence_rate, case_fatality_rate
FROM country_cause_of_death_data
WHERE cause_of_death_id = 1 AND year = 2008;

SELECT cause_of_death_name
FROM causes_of_death
WHERE prevalence = (SELECT MAX(prevalence) FROM causes_of_death);

SELECT number_of_deaths
FROM country_disease_data
WHERE country_id = 0 AND disease_id = 0 AND year = 2007;

SELECT injury_name, mortality_rate
FROM injuries
WHERE mortality_rate > (SELECT AVG(mortality_rate) FROM injuries);
